import React, { Component, Fragment } from 'react';
import PropTypes from 'prop-types';
import {connect} from 'react-redux';
import {withStyles} from '@material-ui/core/styles';
import { MyTable, breadCrumbActions, MyDialog } from '../../../includes';
import { insureAdminRouteNames } from '../../routeNames';
import { insureAdminCooperativeActions } from '../actions';
import { insureAdminCooperativeStrings } from '../config';
import { TableCell, Typography, Button } from '@material-ui/core';
import { appActions, alertAction } from '../../../../actions';
import { EndDateBox } from '../Payments/EndDateBox';


const style = theme => ({
    root : {
    },
    cell : {
        padding : 5,
    },
    cellText : {
        fontSize : 12
    },
    cellTextBordered : {
        fontSize : 12,
        border : "solid 1px",
        borderRadius : 5,
        padding : 5,
        textAlign : "center",
    },
    cellBtn : {
        textTransform : "lowercase",
        padding : 5,
        fontSize : 12,
        marginRight : 5,
    }
})
class _Subscribers extends Component {
    constructor(props) {
        super(props);
        this.state = {
            lastId : null,
            rows : 20,
            endDateDialog : false,
            row : null,
        }
        const {dispatch} = props;
        breadCrumbActions.setBreadCrumb([
            {name : "Site", path : insureAdminRouteNames.home},
            {name : "Coopertive", path : insureAdminRouteNames.cooperative}
        ])(dispatch);
    }
    componentDidMount() {
        const {[insureAdminCooperativeStrings.subscribers] : subscribers} = this.props;
        if(!subscribers)
            this.getSubscribers();
    }
    getSubscribers(){
        const {lastId, rows} = this.state;
        const {dispatch} = this.props;
        insureAdminCooperativeActions.getSubscribers(lastId, rows)(dispatch);
    }
    deactivateSubscriber_ = row => e => {
        e.stopPropagation();
        const {dispatch} = this.props;
        appActions.showSnackDialog("Are you sure you want to deactive subscriber("+row.lastName+")",
            <Button key="deactivate" onClick={this.deactivateSubscriber(row)}>Continue</Button>
        )(dispatch);
    }
    deactivateSubscriber = row => e => {
        const {dispatch} = this.props;
        appActions.closeSnackDialog()(dispatch);
        insureAdminCooperativeActions.deactivateSubscriber(row._id, done=>{
            if(done) this.getSubscribers();
        })(dispatch);
    }
    suspendSubscriber_ = row => e => {
        e.stopPropagation();
        const {dispatch} = this.props;
        appActions.showSnackDialog("Are you sure you want to suspend subscriber("+row.lastName+")",
            <Button key="deactivate" onClick={this.suspendSubscriber(row)}>Continue</Button>
        )(dispatch);
    }
    suspendSubscriber = row => e => {
        const {dispatch} = this.props;
        appActions.closeSnackDialog()(dispatch);
        insureAdminCooperativeActions.suspendSubscriber(row._id, done => {
            if(done) this.getSubscribers();
        })(dispatch);
    }
    unsuspendSubscriber_ = row => e => {
        e.stopPropagation();
        const {dispatch} = this.props;
        appActions.showSnackDialog("Are you sure you want to unsuspend subscriber("+row.lastName+")",
            <Button key="deactivate" onClick={this.unsuspendSubscriber(row)}>Continue</Button>
        )(dispatch);
    }
    unsuspendSubscriber = row => () => {
        const {dispatch} = this.props;
        appActions.closeSnackDialog()(dispatch);
        insureAdminCooperativeActions.unsuspendSubscriber(row._id, done => {
            if(done) this.getSubscribers();
        })(dispatch);
    }
    cellMapFormat = props => ({row, cellMap}) => {
        const {classes} = this.props;
        const status = new Date(row.expDate) > new Date();
        switch(cellMap){
            case "action" : return <TableCell className={classes.cell}>                
                {!row.suspended ? 
                    <Fragment>
                        {status ? 
                        <Button variant="outlined" 
                            classes={{root : classes.cellBtn}} 
                            color="secondary"
                            onClick={this.deactivateSubscriber_(row)}>Deactivate</Button>:
                        <Button variant="outlined" 
                        classes={{root : classes.cellBtn}}
                        color="primary"
                        onClick={this.openEndDateDialog(row)}>Activate</Button>}
                        <Button variant="outlined" 
                            classes={{root : classes.cellBtn}}
                            style={{color : "#ff5722"}}
                            onClick={this.suspendSubscriber_(row)}
                            color="secondary">Suspend</Button>
                    </Fragment> : 
                    <Button variant="outlined" 
                        classes={{root : classes.cellBtn}}
                        color="primary"
                        onClick={this.unsuspendSubscriber_(row)}>Unsuspend</Button>
                }
            </TableCell>
            case "status" : return <TableCell className={classes.cell}>
                <div style={{display : "flex"}}>{
                    row.suspended ? 
                    <Typography className={classes.cellTextBordered} style={{
                        color : "#ff5722"
                    }}>Suspended</Typography> :
                    (status? 
                    <Typography className={classes.cellTextBordered} style={{
                        color : "green"
                    }}>Active</Typography> : 
                    <Typography className={classes.cellTextBordered} style={{
                        color : "red"
                    }}>Inactive</Typography>)
                }</div>
            </TableCell>;
            default : return <TableCell className={classes.cell}>
                <Typography className={classes.cellText}>{row[cellMap]}</Typography>
            </TableCell>
        }
    }
    notify(message, type){
        const {dispatch} = this.props;
        appActions.showSnackbar(
            alertAction[type](message)
        )(dispatch);
    }
    openEndDateDialog = row => e => {
        e.stopPropagation();
        this.setState({row, endDateDialog : true})
    }
    setExpirationDate = row => expDate => {
        const {dispatch} = this.props;
        this.setState({endDateDialog : false});
        appActions.showSnackDialog(
            "Are you sure you want to activate subscriber ("+row.lastName+")",
            <Button key="activateSub" 
                onClick={this.activateSubscriber(row, expDate)}
            >Continue</Button>
        )(dispatch)
    }
    activateSubscriber = (row, expDate) => () => {
        const {dispatch} = this.props;
        appActions.closeSnackDialog()(dispatch);
        insureAdminCooperativeActions.activateSubscriber(row._id, expDate, done=>{
            if(done) this.getSubscribers();
        })(dispatch);
    }
    render() {
        const {
            classes,
            [insureAdminCooperativeStrings.subscribers] : subscribers
        } = this.props;
        const {endDateDialog, row} = this.state;
        return (
            <div className={classes.root}>
                <MyTable
                    header={["Name", "Email", "Phone", "Status", "Actions"]}
                    dataMap={["fullName", "email", "phone", "status", "action"]}
                    data={subscribers}
                    CellMap={this.cellMapFormat({})}
                    />
                <MyDialog 
                    open={endDateDialog}
                    close={()=>this.setState({endDateDialog : false})}>
                    <EndDateBox
                        notify={this.notify.bind(this)}
                        setExpiration={this.setExpirationDate(row)}/>
                </MyDialog>
            </div>
        );
    }
}


_Subscribers.propTypes = {
    classes : PropTypes.object.isRequired
};

const mapStateToProps = ({insureAdminCooperativeReducer}) => ({
    [insureAdminCooperativeStrings.subscribers] : insureAdminCooperativeReducer[insureAdminCooperativeStrings.subscribers],
})


export const Subscribers = connect(mapStateToProps)(withStyles(style)(_Subscribers));
export {Subscribers as default}