import React, { Component } from 'react';
import PropTypes from 'prop-types';
import {connect} from 'react-redux';
import {withStyles} from '@material-ui/core/styles';
import { insureAdminCooperativeActions } from '../actions';
import { MyTable, MyDialog } from '../../../includes';
import { insureAdminCooperativeStrings } from '../config';
import { FormControl, InputLabel, Select, MenuItem, TableCell, Typography, Button } from '@material-ui/core';
import { appActions, alertAction } from '../../../../actions';
import { Delete } from '@material-ui/icons';
import { EndDateBox } from './EndDateBox';
import { monthSelections } from '../../../../utils';


const style = theme => ({
    root: {
    },
    button : {
        textTransform : "lowercase",
        padding : 5,
    }
})
class _Payments extends Component {
    constructor(props) {
        super(props);
        this.state = {
            lastId : null,
            rows : 20,
            option : "all",
            endDateDialog : false,
            row : null,
        }
    }
    
    componentDidMount() {
        this.getPayments();
    }
    getPayments(){
        const {lastId, rows} = this.state;
        const {dispatch} = this.props;
        insureAdminCooperativeActions.getPayments(lastId, rows)(dispatch);
    }
    optionChange(e){
        const value = e.target.value;
        this.setState({option : value})
    }
    sieveOptions(data, option){
        let newData = [];
        if(data) for (let i = 0; i < data.length; i++) {
            const item = data[i];
            if(option === "approved" && item.status === "approved")
                newData.push(item);
            else if (option === "requests" && (!item.status || item.status === false))
                newData.push(item);
            else if (option === "all")
                newData.push(item);
        }
        return newData;
    }
    approveRequest_ = (row, expDate) => {
        const {dispatch} = this.props;
        appActions.showSnackDialog(
            "Are you sure you want to approve this payment?",
            <Button key={"approvePayment"} 
                onClick={this.approveRequest(
                    row._id, row.userid ? 
                        parseInt(row.userid) : 
                        row.userId, 
                    expDate)}>
                    Continue
            </Button>
        )(dispatch);
    }
    approveRequest = (id, userId, expDate)=> ()=> {
        const {dispatch} = this.props;
        appActions.closeSnackDialog()(dispatch);
        insureAdminCooperativeActions.approveRequest(id, userId, expDate, done => {
            if(done) this.getPayments();
        })(dispatch)
    }
    deleteRequest_ = row => e => {
        e.stopPropagation();
        e.preventDefault();
        const {dispatch} = this.props;
        appActions.showSnackDialog(
            "Are you sure you want to delete this payment?",
            <Button key={"approvePayment"} 
                onClick={this.deleteRequest(row._id)}>
                    Continue
            </Button>
        )(dispatch);
    }
    deleteRequest = id => () => {
        const {dispatch} = this.props;
        appActions.closeSnackDialog()(dispatch);
        insureAdminCooperativeActions.deleteRequest(id, done => {
            if(done) this.getPayments();
        })(dispatch);
    }
    openEndDateDialog=row=>()=>{
        this.setState({row, endDateDialog :true});
    }
    cellMapFormat = props => ({row, cellMap}) => {
        const {classes} = this.props;
        switch(cellMap){
            case "delete" : return <TableCell className={classes.cell}>
                <Delete color="secondary" onClick={this.deleteRequest_(row)}/>
            </TableCell>
            case "action" : return <TableCell className={classes.cell}>
                {!row.status || row.status !== "approved" ? 
                <Button
                    classes={{
                        root : classes.button
                    }}
                    variant="contained"
                    onClick={this.openEndDateDialog(row)}
                    color="primary">approve</Button> : 
                    <Typography color="textPrimary" style={{
                        fontSize : 10,
                        padding : 5,
                        border : "solid 1px green",
                        borderRadius : 5,
                        color : "green",
                    }}>Approved</Typography>
                }
            </TableCell>
            case "months" : 
                const {item : monthItem} = monthSelections.getFirstObjectByPropValue("value", row[cellMap]) || {};
                return <TableCell className={classes.cell}>
                <Typography style={{
                    fontSize : 12
                }}>{monthItem ? monthItem.name : null}</Typography>
            </TableCell>
            default : return <TableCell className={classes.cell}>
                <Typography style={{
                    fontSize : 12
                }}>{row[cellMap]}</Typography>
            </TableCell>
        }
    }
    notify(message, type){
        const {dispatch} = this.props;
        appActions.showSnackbar(
            alertAction[type](message)
        )(dispatch);
    }
    setExpiration = row => (expDate)=>{
        this.setState({endDateDialog : false});
        console.log(row); 
        this.approveRequest_(row, expDate);
    }
    render() {
        const {
            classes,
            [insureAdminCooperativeStrings.payments] : payments
        } = this.props;
        const {option, endDateDialog, row} = this.state;
        return (
            <div className={classes.root}>
                <MyDialog
                    open={endDateDialog}
                    close={()=>this.setState({endDateDialog : false})}>
                        <EndDateBox
                            notify={this.notify.bind(this)}
                            setExpiration={this.setExpiration(row)}/>
                    </MyDialog>
                <FormControl>
                    <InputLabel htmlFor="options">Options</InputLabel>
                    <Select
                        value={String(option)}
                        onChange={e=>this.optionChange(e)}
                        inputProps={{
                            id : "options"
                        }}>
                            {[
                                {name : "All", value : "all"},
                                {name : "Requests", value : "requests"},
                                {name : "Approved", value : "approved"}
                            ].map((item, index)=>{

                                return <MenuItem value={item.value} key={index}>{item.name}</MenuItem>
                            })}
                        </Select>
                </FormControl>
                <MyTable
                    header={["Name", "Phone", "Method", "Duration", "Transaction ID", "Start Month", "Amount", "Actions", "Delete"]}
                    dataMap={["name", "phone", "method", "duration", "transactionId", "months", "amount", "action", "delete"]}
                    data={this.sieveOptions(payments, option)}
                    CellMap={this.cellMapFormat({})}
                    />
            </div>
        );
    }
}


_Payments.propTypes = {
    classes : PropTypes.object.isRequired
};
const mapStateToProps = ({insureAdminCooperativeReducer}) => ({
    [insureAdminCooperativeStrings.payments] : insureAdminCooperativeReducer[insureAdminCooperativeStrings.payments]
})


export const Payments = connect(mapStateToProps)(withStyles(style)(_Payments));
export {Payments as default}