import React, { Component } from 'react';
import PropTypes from 'prop-types';
import {withStyles} from '@material-ui/core/styles';
import { FormLabel, Button } from '@material-ui/core';
import { HighlightedInfo } from '../../../../includes';
import { TimerOff } from '@material-ui/icons';
const style = theme => ({
    root: {
        marginTop : 20,
        display : "flex",
        flexDirection : "column",
        alignItems : 'center',
    }
})
class _EndDateBox extends Component {
    constructor(props) {
        super(props);
        this.state = {
            value : "",
        }
    }
    onClick(){
        const {value} = this.state;
        const {notify, setExpiration} = this.props;
        if(!String(value)){
            if(notify) notify("Invalid expiration date", "error");
            return;
        }
        if(setExpiration) setExpiration(new Date(value));
    }
    render() {
        const {classes} = this.props;
        const {value} = this.state;
        return (
            <div className={classes.root}>
                <FormLabel>Expiration Date</FormLabel>
                <HighlightedInfo>This is the duration after which the subscriber will be inactive. and will need to re-subscribe</HighlightedInfo>
                <input type="date" 
                    style={{
                        padding : 10
                    }}
                    value={value} 
                    onChange={e=>this.setState({value :e.target.value})}/>
                <Button
                    style={{marginTop : 20}}
                    variant="contained"
                    color="primary"
                    onClick={()=>this.onClick()}>
                        <TimerOff/> Set Expiration
                    </Button>
            </div>
        );
    }
}
_EndDateBox.propTypes = {
    classes : PropTypes.object.isRequired,
    notify : PropTypes.func,
    setExpiration : PropTypes.func,
};
export const EndDateBox = withStyles(style)(_EndDateBox);