import React, { Component } from 'react';
import PropTypes from 'prop-types';
import {connect} from 'react-redux';
import {withStyles} from '@material-ui/core/styles';
import { MyCustomTabs, breadCrumbActions } from '../../includes';
import { Subscribers } from './Subscribers';
import { Payments } from './Payments';
import { insureAdminRouteNames } from '../routeNames';


const style = theme => ({
    root: {
        
    },
    tabRoot : {
        marginTop : 10,
    },
    container : {
        padding : 20,
    }
})
class _Cooperative extends Component {
    constructor(props) {
        super(props);
        this.state = {
            tabValue : null
        }
        const {dispatch} = props;
        breadCrumbActions.setBreadCrumb([
            {name : "Site", path : insureAdminRouteNames.home},
            {name : "Cooperative", path : insureAdminRouteNames.cooperative}
        ])(dispatch);
    }
    
    render() {
        const {classes} = this.props;
        const {tabValue} = this.state;
        return (
            <div className={classes.root}>
                <MyCustomTabs
                    classes={{
                        root : classes.tabRoot
                    }}
                    position="sticky"
                    tabs={{
                        subscribers : "Subscribers",
                        payments : "Payments",
                    }}
                    getInitialTabValue={tabValue=>this.setState({tabValue})}/>
                <div className={classes.container}>
                    {tabValue === "subscribers" && <Subscribers/>}
                    {tabValue === "payments" && <Payments/>}                    
                </div>
            </div>
        );
    }
}


_Cooperative.propTypes = {
    classes : PropTypes.object.isRequired
};
const mapStateToProps = state => ({
    state
})


export const Cooperative = connect(mapStateToProps)(withStyles(style)(_Cooperative));
export {Cooperative as default}